class Solution:
    def countGoodIntegersOnPath(self, l: int, r: int, directions: str) -> int:
        row = col = 0
        path = [row * 4 + col]
        for ch in directions:
            if ch == 'D':
                row += 1
            else:
                col += 1
            path.append(row * 4 + col)
        path_set = set(path)

        def count_le(n):
            if n < 0:
                return 0
            digits = [int(ch) for ch in f'{n:016d}']
            memo = {}

            def dp(pos, tight, last):
                if pos == 16:
                    return 1
                key = (pos, tight, last)
                if not tight and key in memo:
                    return memo[key]
                limit = digits[pos] if tight else 9
                total = 0
                for d in range(limit + 1):
                    if pos in path_set:
                        if last is not None and d < last:
                            continue
                        nl = d
                    else:
                        nl = last
                    total += dp(pos + 1, tight and d == limit, nl)
                if not tight:
                    memo[key] = total
                return total

            return dp(0, True, None)

        return count_le(r) - count_le(l - 1)

