var countGoodIntegersOnPath = function(l, r, directions) {
    let row = 0, col = 0;
    const path = [row * 4 + col];
    for (const ch of directions) {
        if (ch === 'D') row += 1; else col += 1;
        path.push(row * 4 + col);
    }
    const pathSet = new Set(path);

    function countLe(n) {
        if (n < 0) return 0;
        const s = n.toString().padStart(16, '0');
        const digits = [...s].map(Number);
        const memo = new Map();

        function dp(pos, tight, last) {
            if (pos === 16) return 1;
            const key = pos + ',' + (tight ? 1 : 0) + ',' + (last === null ? -1 : last);
            if (!tight && memo.has(key)) return memo.get(key);
            const limit = tight ? digits[pos] : 9;
            let total = 0;
            for (let d = 0; d <= limit; d++) {
                let nl;
                if (pathSet.has(pos)) {
                    if (last !== null && d < last) continue;
                    nl = d;
                } else {
                    nl = last;
                }
                total += dp(pos + 1, tight && d === limit, nl);
            }
            if (!tight) memo.set(key, total);
            return total;
        }

        return dp(0, true, null);
    }

    return countLe(r) - countLe(l - 1);
};
